Identify compaction opportunities in this Go function:

```go
func GetUserByEmail(db *sql.DB, email string) (*User, error) {
    // Create the SQL query string
    queryString := "SELECT id, name, email, created_at FROM users WHERE email = ?"

    // Execute the query against the database
    rows, err := db.Query(queryString, email)
    if err != nil {
        // Return nil and the error
        return nil, err
    }

    // Make sure we close the rows when done
    defer rows.Close()

    // Check if we got any rows
    hasRows := rows.Next()
    if hasRows == false {
        return nil, nil
    }

    // Create a new user struct to hold the data
    var user User

    // Scan the row into the user struct
    scanErr := rows.Scan(&user.ID, &user.Name, &user.Email, &user.CreatedAt)
    if scanErr != nil {
        return nil, scanErr
    }

    // Return the user and no error
    return &user, nil
}
