func validatePassword(password: String) -> (isValid: Bool, errors: [String]) {
    // Create array to hold error messages
    var errorMessages: [String] = []

    // Check minimum length requirement
    let minimumLength = 8
    let passwordLength = password.count
    let isTooShort = passwordLength < minimumLength
    if isTooShort == true {
        errorMessages.append("Password must be at least 8 characters")
    }

    // Check for uppercase letter
    var hasUppercase = false
    for character in password {
        if character.isUppercase {
            hasUppercase = true
        }
    }
    if hasUppercase == false {
        errorMessages.append("Password must contain an uppercase letter")
    }

    // Check for digit
    var hasDigit = false
    for character in password {
        if character.isNumber {
            hasDigit = true
        }
    }
    if hasDigit == false {
        errorMessages.append("Password must contain a number")
    }

    // Determine if valid
    let isValid = errorMessages.isEmpty
    let validationResult = (isValid: isValid, errors: errorMessages)
    return validationResult
}
